143→export const clipboardDb = {
144→  async getAll(limit = 1000): Promise<ClipboardEntryRow[]> {
145→    if (isTauri) {
146→      const db = await getDb();
147→      return db.select<ClipboardEntryRow[]>(
148→        'SELECT id, content, content_type, source_app, copied_at, pinned FROM clipboard_entries ORDER BY pinned DESC, copied_at DESC LIMIT $1',
149→        [limit],
150→      );
151→    }
152→    return storageGet('clipboard-history', isClipboardRowArray) ?? [];
153→  },
154→  async insert(entry: ClipboardEntryRow): Promise<void> {
155→    if (isTauri) {
156→      const db = await getDb();
157→      await db.execute(
158→        'INSERT INTO clipboard_entries (id, content, content_type, source_app, copied_at, pinned) VALUES ($1, $2, $3, $4, $5, $6)',
159→        [
160→          entry.id,
161→          entry.content,
162→          entry.content_type,
163→          entry.source_app,
164→          entry.copied_at,
165→          entry.pinned,
166→        ],
167→      );
168→      return;
169→    }
170→    const all = await this.getAll();
171→    all.unshift(entry);
172→    storageSet('clipboard-history', all);
173→  },
174→  async update(
175→    id: string,
176→    updates: Partial<Omit<ClipboardEntryRow, 'id'>>,
177→  ): Promise<void> {
178→    if (isTauri) {
179→      const db = await getDb();
180→      const fields: string[] = [];
181→      const values: unknown[] = [];
182→      let idx = 1;
183→
184→      for (const [key, value] of Object.entries(updates)) {
185→        fields.push(`${key} = $${idx}`);
186→        values.push(value);
187→        idx++;
188→      }
189→
190→      if (fields.length === 0) return;
191→      values.push(id);
192→      await db.execute(
193→        `UPDATE clipboard_entries SET ${fields.join(', ')} WHERE id = $${idx}`,
194→        values,
195→      );
196→      return;
197→    }
198→    const all = await this.getAll();
199→    const updated = all.map(r =>
200→      r.id === id
201→        ? {
202→            ...r,
203→            ...updates,
204→          }
205→        : r);
206→    storageSet('clipboard-history', updated);
207→  },
208→  async delete(id: string): Promise<void> {
209→    if (isTauri) {
210→      const db = await getDb();
211→      await db.execute('DELETE FROM clipboard_entries WHERE id = $1', [id]);
212→      return;
213→    }
214→    const all = await this.getAll();
215→    storageSet(
216→      'clipboard-history',
217→      all.filter(r => r.id !== id),
218→    );
219→  },
220→  async clear(): Promise<void> {
221→    if (isTauri) {
222→      const db = await getDb();
223→      await db.execute('DELETE FROM clipboard_entries', []);
224→      return;
225→    }
226→    storageRemove('clipboard-history');
227→  },
228→  async search(query: string, limit = 50): Promise<ClipboardEntryRow[]> {
229→    if (isTauri) {
230→      const db = await getDb();
231→      return db.select<ClipboardEntryRow[]>(
232→        `SELECT ce.id, ce.content, ce.content_type, ce.source_app, ce.copied_at, ce.pinned
233→         FROM clipboard_entries ce
234→         JOIN clipboard_entries_fts fts ON ce.rowid = fts.rowid
235→         WHERE clipboard_entries_fts MATCH $1
236→         ORDER BY ce.pinned DESC, ce.copied_at DESC
237→         LIMIT $2`,
238→        [
239→          query,
240→          limit,
241→        ],
242→      );
243→    }
244→    const all = await this.getAll();
245→    const q = query.toLowerCase();
246→    return all.filter(r => r.content.toLowerCase().includes(q)).slice(0, limit);
247→  },
248→};
