615→      const db = await getDb();
616→      const rows = await db.select<SettingRow[]>(
617→        'SELECT value FROM settings WHERE key = $1',
618→        [key],
619→      );
620→      return rows[0]?.value ?? null;
621→    }
622→    const all = storageGet('settings-all', isSettingRowArray);
623→    return all?.find(r => r.key === key)?.value ?? null;
624→  },
625→  async set(key: string, value: string): Promise<void> {
626→    if (isTauri) {
627→      const db = await getDb();
628→      await db.execute(
629→        'INSERT INTO settings (key, value) VALUES ($1, $2) ON CONFLICT(key) DO UPDATE SET value = $2',
630→        [
631→          key,
632→          value,
633→        ],
634→      );
635→      return;
636→    }
637→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
638→    const existing = all.findIndex(r => r.key === key);
639→    if (existing >= 0) {
640→      all[existing] = {
641→        key,
642→        value,
643→      };
644→    } else {
645→      all.push({
646→        key,
647→        value,
648→      });
649→    }
650→    storageSet('settings-all', all);
651→  },
652→  async delete(key: string): Promise<void> {
653→    if (isTauri) {
654→      const db = await getDb();
655→      await db.execute('DELETE FROM settings WHERE key = $1', [key]);
656→      return;
657→    }
658→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
659→    storageSet(
660→      'settings-all',
661→      all.filter(r => r.key !== key),
662→    );
663→  },
664→  async getAll(): Promise<SettingRow[]> {
665→    if (isTauri) {
666→      const db = await getDb();
667→      return db.select<SettingRow[]>('SELECT key, value FROM settings');
668→    }
669→    return storageGet('settings-all', isSettingRowArray) ?? [];
670→  },
671→};
